","export class BrunchService {
 constructor() {
 this.tableName = "x_22750_brunch_coo_brunch_item";
 }

 // Get all brunch items with display values
 async list(filters = {}) {
 try {
 const searchParams = new URLSearchParams(filters);
 searchParams.set('sysparm_display_value', 'all');
 searchParams.set('sysparm_limit', '1000');

 const response = await fetch(`/api/now/table/${this.tableName}?${searchParams.toString()}`, {
 method: "GET",
 headers: {
 "Accept": "application/json",
 "X-UserToken": window.g_ck
 },
 });

 if (!response.ok) {
 const errorData = await response.json().catch(() => ({}));
 throw new Error(`Failed to fetch items: ${response.status} - ${errorData.error?.message || response.statusText}`);
 }

 const data = await response.json();
 return data.result || [];
 } catch (error) {
 console.error('Error fetching brunch items:', error);
 throw new Error('Failed to load brunch items. Please check your connection and try again.');
 }
 }

 // Create a new brunch item
 async create(itemData) {
 try {
 const response = await fetch(`/api/now/table/${this.tableName}`, {
 method: "POST",
 headers: {
 "Content-Type": "application/json",
 "Accept": "application/json",
 "X-UserToken": window.g_ck
 },
 body: JSON.stringify(itemData),
 });

 if (!response.ok) {
 const errorData = await response.json().catch(() => ({}));
 throw new Error(`Failed to create item: ${response.status} - ${errorData.error?.message || response.statusText}`);
 }

 return await response.json();
 } catch (error) {
 console.error('Error creating brunch item:', error);
 throw new Error('Failed to add brunch item. Please try again.');
 }
 }

 // Update an existing brunch item
 async update(sysId, itemData) {
 try {
 const response = await fetch(`/api/now/table/${this.tableName}/${sysId}`, {
 method: "PATCH",
 headers: {
 "Content-Type": "application/json",
 "Accept": "application/json",
 "X-UserToken": window.g_ck
 },
 body: JSON.stringify(itemData),
 });

 if (!response.ok) {
 const errorData = await response.json().catch(() => ({}));
 throw new Error(`Failed to update item: ${response.status} - ${errorData.error?.message || response.statusText}`);
 }

 return await response.json();
 } catch (error) {
 console.error('Error updating brunch item:', error);
 throw new Error('Failed to update brunch item. Please try again.');
 }
 }

 // Delete a brunch item
 async delete(sysId) {
 try {
 const response = await fetch(`/api/now/table/${this.tableName}/${sysId}`, {
 method: "DELETE",
 headers: {
 "Accept": "application/json",
 "X-UserToken": window.g_ck
 },
 });

 if (!response.ok) {
 const errorData = await response.json().catch(() => ({}));
 throw new Error(`Failed to delete item: ${response.status} - ${errorData.error?.message || response.statusText}`);
 }

 return true;
 } catch (error) {
 console.error('Error deleting brunch item:', error);
 throw new Error('Failed to delete brunch item. Please try again.');
 }
 }

 // Get items by category
 async getByCategory(category) {
 return this.list({ sysparm_query: `category=${category}` });
 }

 // Get items by contributor
 async getByContributor(contributorSysId) {
 return this.list({ sysparm_query: `contributor=${contributorSysId}` });
 }

 // Search items by name or description
