 { value: 'bread', labelKey: 'categories.bread', icon: '🥖' },
 { value: 'savory_pies_cakes_pizza', labelKey: 'categories.savory_pies_cakes_pizza', icon: '🍕' },
 { value: 'salad', labelKey: 'categories.salad', icon: '🥗' },
 { value: 'dessert', labelKey: 'categories.dessert', icon: '🍰' },
 { value: 'other', labelKey: 'categories.other', icon: '🍽️' }
 ];

 const DIETARY_LABELS = [
 { key: 'is_halal', labelKey: 'dietary.halal', icon: '☪️' },
 { key: 'is_vegan', labelKey: 'dietary.vegan', icon: '🌱' },
 { key: 'is_vegetarian', labelKey: 'dietary.vegetarian', icon: '🥬' },
 { key: 'is_gluten_free', labelKey: 'dietary.glutenFree', icon: '🌾' }
 ];

 const [formData, setFormData] = useState({
