 is_vegetarian: false,
 is_gluten_free: false
 });
 const [isSubmitting, setIsSubmitting] = useState(false);
 const [error, setError] = useState(null);

 const handleChange = (e) => {
 const { name, value, type, checked } = e.target;
 setFormData(prev => ({
 ...prev,
 [name]: type === 'checkbox' ? checked : value
 }));
 };

 const handleSubmit = async (e) => {
 e.preventDefault();
 setIsSubmitting(true);
 setError(null);

 try {
 await service.create(formData);

 // Reset form but keep the person's name for convenience
 setFormData(prev => ({
 item_name: '',
 description: '',
 category: '',
 quantity: '',
 notes: '',
 brought_by: prev.brought_by, // Keep the person's name for next entry
 is_halal: false,
 is_vegan: false,
 is_vegetarian: false,
 is_gluten_free: false
 }));
 onAdd();
 } catch (err) {
 setError(t('failedToAdd'));
 console.error('Error creating item:', err);
 } finally {
 setIsSubmitting(false);
 }
 };

 return (
 <div className="brunch-form-container">
 <div className="form-header">
 <h2>🍽️ {t('addItemTitle')}</h2>
 <p>{t('addItemSubtitle')}</p>
