 id="brought_by"
 name="brought_by"
 value={formData.brought_by}
 onChange={handleChange}
 placeholder={t('enterYourName')}
 required
 className="form-input"
 />
 </div>

 <div className="form-group">
 <label htmlFor="item_name">🍽️ {t('itemName')} *</label>
 <input
