import { useLanguage } from '../app.jsx';
import './BrunchItem.css';

const CATEGORY_ICONS = {
 appetizer: '🥨',
 drinks: '☕',
 cheese: '🧀',
 bread: '🥖',
 savory_pies_cakes_pizza: '🍕',
 salad: '🥗',
 dessert: '🍰',
 other: '🍽️'
};

const DIETARY_ICONS = {
 is_halal: { icon: '☪️', labelKey: 'dietary.halal' },
 is_vegan: { icon: '🌱', labelKey: 'dietary.vegan' },
 is_vegetarian: { icon: '🥬', labelKey: 'dietary.vegetarian' },
 is_gluten_free: { icon: '🌾', labelKey: 'dietary.glutenFree' }
};

export default function BrunchItem({ item, service, onChange }) {
 const { t } = useLanguage();
 const [isDeleting, setIsDeleting] = useState(false);

 // Extract values safely from ServiceNow objects
 const itemName = typeof item.item_name === 'object' ? item.item_name.display_value : item.item_name;
 const description = typeof item.description === 'object' ? item.description.display_value : item.description;
 const category = typeof item.category === 'object' ? item.category.display_value : item.category;
 const quantity = typeof item.quantity === 'object' ? item.quantity.display_value : item.quantity;
 const broughtBy = typeof item.brought_by === 'object' ? item.brought_by.display_value : item.brought_by;
 const notes = typeof item.notes === 'object' ? item.notes.display_value : item.notes;
 const sysId = typeof item.sys_id === 'object' ? item.sys_id.value : item.sys_id;

 // Extract dietary flags
 const isHalal = String(typeof item.is_halal === 'object' ? item.is_halal.display_value : item.is_halal) === 'true';
 const isVegan = String(typeof item.is_vegan === 'object' ? item.is_vegan.display_value : item.is_vegan) === 'true';
 const isVegetarian = String(typeof item.is_vegetarian === 'object' ? item.is_vegetarian.display_value : item.is_vegetarian) === 'true';
 const isGlutenFree = String(typeof item.is_gluten_free === 'object' ? item.is_gluten_free.display_value : item.is_gluten_free) === 'true';

 const activeDietary = [];
 if (isHalal) activeDietary.push(DIETARY_ICONS.is_halal);
 if (isVegan) activeDietary.push(DIETARY_ICONS.is_vegan);
 if (isVegetarian) activeDietary.push(DIETARY_ICONS.is_vegetarian);
 if (isGlutenFree) activeDietary.push(DIETARY_ICONS.is_gluten_free);

 // Get translated category name
 const categoryNames = {
 appetizer: 'categories.appetizer',
 drinks: 'categories.drinks',
 cheese: 'categories.cheese',
 bread: 'categories.bread',
 savory_pies_cakes_pizza: 'categories.savory_pies_cakes_pizza',
 salad: 'categories.salad',
 dessert: 'categories.dessert',
 other: 'categories.other'
 };

 const categoryDisplayName = categoryNames[category] ? t(categoryNames[category]) : category;

 const handleDelete = async () => {
 if (!window.confirm(t('confirmDelete', { itemName }))) {
 return;
 }

 setIsDeleting(true);
 try {
 await service.delete(sysId);
 onChange();
 } catch (err) {
 console.error('Error deleting item:', err);
 alert(t('failedToDelete'));
 } finally {
 setIsDeleting(false);
 }
 };

 return (
 <div className={`brunch-item ${isDeleting ? 'deleting' : ''}`}>
 <div className="item-header">
 <div className="item-title">
 <span className="category-icon">
 {CATEGORY_ICONS[category] || '🍽️'}
 </span>
 <h3>{itemName || 'Untitled Item'}</h3>
 </div>
 <button 
 onClick={handleDelete} 
 className="delete-btn"
 disabled={isDeleting}
 title={t('removeItem')}
 >
 {isDeleting ? '⏳' : '✕'}
 </button>
 </div>

 {description && (
 <p className="item-description">{description}</p>
 )}

 <div className="item-details">
 {broughtBy && (
 <div className="detail-item">
 <span className="detail-label">👤 {t('broughtBy')}</span>
 <span className="detail-value">{broughtBy}</span>
 </div>
 )}

 {quantity && (
 <div className="detail-item">
 <span className="detail-label">📊 {t('quantityLabel')}</span>
 <span className="detail-value">{quantity}</span>
 </div>
 )}

 {category && (
 <div className="detail-item">
 <span className="detail-label">🏷️ {t('categoryLabel')}</span>
 <span className="detail-value category-badge">
 {CATEGORY_ICONS[category] || '🍽️'} 
 {categoryDisplayName}
 </span>
 </div>
 )}
 </div>

 {activeDietary.length > 0 && (
 <div className="dietary-info">
 <span className="dietary-label">{t('dietaryLabel')}</span>
 <div className="dietary-badges">
 {activeDietary.map((diet, index) => (
 <span key={index} className="dietary-badge" title={t(diet.labelKey)}>
 {diet.icon} {t(diet.labelKey)}
 </span>
 ))}
 </div>
 </div>
 )}

 {notes && (
 <div className="item-notes">
 <span className="notes-label">📝 {t('notesLabel')}</span>
 <p className="notes-text">{notes}</p>
 </div>
 )}
 </div>
 );
}",".brunch-list-container {
