 salad: '🥗',
 dessert: '🍰',
 other: '🍽️'
};

const DIETARY_ICONS = {
 is_halal: { icon: '☪️', labelKey: 'dietary.halal' },
 is_vegan: { icon: '🌱', labelKey: 'dietary.vegan' },
 is_vegetarian: { icon: '🥬', labelKey: 'dietary.vegetarian' },
 is_gluten_free: { icon: '🌾', labelKey: 'dietary.glutenFree' }
};

export default function BrunchList({ items, service, onChange, loading }) {
 const { t } = useLanguage();

 const CATEGORIES = [
 { value: '', labelKey: 'allCategories' },
 { value: 'appetizer', labelKey: 'categories.appetizer', icon: '🥨' },
 { value: 'drinks', labelKey: 'categories.drinks', icon: '☕' },
 { value: 'cheese', labelKey: 'categories.cheese', icon: '🧀' },
 { value: 'bread', labelKey: 'categories.bread', icon: '🥖' },
 { value: 'savory_pies_cakes_pizza', labelKey: 'categories.savory_pies_cakes_pizza', icon: '🍕' },
 { value: 'salad', labelKey: 'categories.salad', icon: '🥗' },
 { value: 'dessert', labelKey: 'categories.dessert', icon: '🍰' },
 { value: 'other', labelKey: 'categories.other', icon: '🍽️' }
 ];

 const DIETARY_FILTERS = [
 { key: 'is_halal', labelKey: 'dietary.halal', icon: '☪️' },
 { key: 'is_vegan', labelKey: 'dietary.vegan', icon: '🌱' },
 { key: 'is_vegetarian', labelKey: 'dietary.vegetarian', icon: '🥬' },
 { key: 'is_gluten_free', labelKey: 'dietary.glutenFree', icon: '🌾' }
 ];

 const [categoryFilter, setCategoryFilter] = useState('');
 const [dietaryFilters, setDietaryFilters] = useState({
 is_halal: false,
 is_vegan: false,
 is_vegetarian: false,
 is_gluten_free: false
 });
 const [searchTerm, setSearchTerm] = useState('');
 const [viewMode, setViewMode] = useState('cards'); // 'cards' or 'list'

 const filteredItems = useMemo(() => {
 return items.filter(item => {
 // Extract values safely
 const itemName = typeof item.item_name === 'object' ? item.item_name.display_value : item.item_name;
 const description = typeof item.description === 'object' ? item.description.display_value : item.description;
 const category = typeof item.category === 'object' ? item.category.display_value : item.category;

 // Category filter
 if (categoryFilter && category !== categoryFilter) {
 return false;
 }

 // Search filter
 if (searchTerm) {
 const searchLower = searchTerm.toLowerCase();
 const nameMatch = itemName && itemName.toLowerCase().includes(searchLower);
 const descMatch = description && description.toLowerCase().includes(searchLower);
 if (!nameMatch && !descMatch) {
 return false;
 }
 }

 // Dietary filters - item must have ALL selected dietary attributes
 const activeDietaryFilters = Object.entries(dietaryFilters).filter(([_, active]) => active);
 if (activeDietaryFilters.length > 0) {
 return activeDietaryFilters.every(([key]) => {
 const itemValue = typeof item[key] === 'object' ? item[key].display_value : item[key];
 return String(itemValue) === 'true';
 });
 }

 return true;
 });
 }, [items, categoryFilter, dietaryFilters, searchTerm]);

 const handleDietaryFilterChange = (key) => {
 setDietaryFilters(prev => ({
