 alert(t('failedToDelete'));
 }
 };

 const renderListItem = (item) => {
 const itemName = typeof item.item_name === 'object' ? item.item_name.display_value : item.item_name;
 const description = typeof item.description === 'object' ? item.description.display_value : item.description;
 const category = typeof item.category === 'object' ? item.category.display_value : item.category;
 const quantity = typeof item.quantity === 'object' ? item.quantity.display_value : item.quantity;
 const broughtBy = typeof item.brought_by === 'object' ? item.brought_by.display_value : item.brought_by;
 const sysId = typeof item.sys_id === 'object' ? item.sys_id.value : item.sys_id;

 // Extract dietary flags
 const isHalal = String(typeof item.is_halal === 'object' ? item.is_halal.display_value : item.is_halal) === 'true';
 const isVegan = String(typeof item.is_vegan === 'object' ? item.is_vegan.display_value : item.is_vegan) === 'true';
 const isVegetarian = String(typeof item.is_vegetarian === 'object' ? item.is_vegetarian.display_value : item.is_vegetarian) === 'true';
 const isGlutenFree = String(typeof item.is_gluten_free === 'object' ? item.is_gluten_free.display_value : item.is_gluten_free) === 'true';

 const activeDietary = [];
 if (isHalal) activeDietary.push(DIETARY_ICONS.is_halal);
 if (isVegan) activeDietary.push(DIETARY_ICONS.is_vegan);
 if (isVegetarian) activeDietary.push(DIETARY_ICONS.is_vegetarian);
 if (isGlutenFree) activeDietary.push(DIETARY_ICONS.is_gluten_free);

 const handleDeleteItem = async () => {
 if (!window.confirm(t('confirmDelete', { itemName }))) {
 return;
 }
 await handleDelete(sysId);
 };

 // Get translated category name
 const categoryTranslation = CATEGORIES.find(cat => cat.value === category);
 const categoryDisplayName = categoryTranslation ? t(categoryTranslation.labelKey) : category;

 return (
 <div key={sysId} className="list-item">
