 </div>
 );
 };

 const hasActiveFilters = categoryFilter || Object.values(dietaryFilters).some(v => v) || searchTerm;

 return (
 <div className="brunch-list-container">
 <div className="list-header">
 <div className="list-title-section">
 <h2>{t('brunchItems')} ({filteredItems.length})</h2>
 <p>{t('brunchItemsSubtitle')}</p>
 </div>

 <div className="view-toggle">
