 className={`dietary-filter ${dietaryFilters[diet.key] ? 'active' : ''}`}
 >
 <span className="filter-icon">{diet.icon}</span>
 <span className="filter-label">{t(diet.labelKey)}</span>
 </button>
 ))}
 </div>

 {hasActiveFilters && (
 <button onClick={clearAllFilters} className="clear-filters">
 {t('clearFilters')}
 </button>
 )}
 </div>

 <div className="items-display">
 {loading ? (
 <div className="loading-items">{t('loadingItems')}</div>
 ) : filteredItems.length === 0 ? (
