 // Get saved language from localStorage or default to English
 return localStorage.getItem('brunch-app-language') || 'en';
 });

 const t = (key, params = {}) => {
 let translation = getTranslation(language, key);
 // Replace parameters in translation
 Object.keys(params).forEach(param => {
 translation = translation.replace(`{${param}}`, params[param]);
 });
 return translation;
 };

 const switchLanguage = (newLang) => {
 setLanguage(newLang);
 localStorage.setItem('brunch-app-language', newLang);
 };

 useEffect(() => { 
 refreshItems();
 }, [svc]);

 const refreshItems = async () => {
 try {
 setLoading(true);
 const brunchItems = await svc.list();
 setItems(brunchItems);
 setError(null);
 } catch (err) {
 setError(t('failedToLoad'));
 console.error('Error loading items:', err);
 } finally {
 setLoading(false);
 }
 };

 const languageContextValue = {
 language,
 setLanguage: switchLanguage,
 t
 };

 if (loading && items.length === 0) {
 return (
 <LanguageContext.Provider value={languageContextValue}>
 <div className="brunch-app">
 <Header />
 <div className="loading">{t('loadingItems')}</div>
 </div>
 </LanguageContext.Provider>
 );
 }

 return (
 <LanguageContext.Provider value={languageContextValue}>
 <div className="brunch-app">
 <Header />

 {error && (
 <div className="error-message">
 {error}
 <button onClick={refreshItems} className="retry-btn">
 {t('tryAgain')}
 </button>
 </div>
 )}

 <div className="main-content">
 <div className="form-section">
 <BrunchForm service={svc} onAdd={refreshItems} />
 </div>

 <div className="list-section">
 <BrunchList 
 items={items} 
 service={svc} 
 onChange={refreshItems}
 loading={loading}
 />
 </div>
 </div>
 </div>
 </LanguageContext.Provider>
 );
}","import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './app.jsx';

ReactDOM.createRoot(document.getElementById("root")).render(
 <React.StrictMode>
 <App />
 </React.StrictMode>
